// PII Masking -- regex SDT VN + ten rieng -> mask tokens
// Outputs BOTH maskedMessage (for logging) and originalMessage (for AI processing)
// CRITICAL-2 fix: AI Agent gets originalMessage with real phone numbers
const triggerData = $input.first().json;
let message = triggerData.data?.content || triggerData.data?.text || '';
const originalMessage = message;
const phoneMap = [];
const nameMap = [];

// 1. Mask VN phone numbers: 0[3|5|7|8|9]xxxxxxxx
const phoneRe = /\b(0[35789]\d{8})\b/g;
message = message.replace(phoneRe, (m) => {
  const id = phoneMap.length;
  phoneMap.push({ mask: `[PHONE_${id}]`, real: m });
  return `[PHONE_${id}]`;
});

// 2. Mask names after keywords
const nameKw = /\b(?:ten|Toi la|Em la|Anh la|Chi la)\s+([A-ZÀ-Ỹ][a-zà-ỹ]{1,15})\b/gi;
message = message.replace(nameKw, (fullMatch, name) => {
  const id = nameMap.length;
  const placeholder = `[NAME_${id}]`;
  nameMap.push({ mask: placeholder, real: name });
  return fullMatch.replace(name, placeholder);
});

return [{
  json: {
    originalMessage: originalMessage,
    maskedMessage: message,
    phoneMap,
    nameMap,
    senderId: triggerData.data?.fromId || triggerData.data?.senderId || 'unknown',
    senderName: triggerData.data?.senderName || 'Khach hang',
    threadId: triggerData.threadId || ''
  }
}];

// Chuan bi context cho AI Agent
// Doc tu PII Masking, forward originalMessage
const priceRows = $input.all();
let priceText = '';
if (priceRows.length > 0) {
  priceText = priceRows.map(r => {
    const svc = r.json['Dich vu'] || r.json['dich_vu'] || r.json['Service'] || '';
    const price = r.json['Gia'] || r.json['gia'] || r.json['Price'] || '';
    const desc = r.json['Mo ta'] || r.json['mo_ta'] || r.json['Description'] || '';
    if (!svc) return '';
    return `- ${svc}: ${price}${desc ? ' -- ' + desc : ''}`;
  }).filter(Boolean).join('\n');
}
if (!priceText) {
  priceText = '(Chua co du lieu gia -- tu van chung, huong khach dat lich)';
}
const piiData = $input.first().json;
return [{
  json: {
    priceSection: priceText,
    customerMessage: piiData.originalMessage || '',
    maskedMessage: piiData.maskedMessage || piiData.originalMessage || '',
    phoneMap: piiData.phoneMap || [],
    nameMap: piiData.nameMap || [],
    originalMessage: piiData.originalMessage || '',
    senderId: piiData.senderId || 'unknown',
    senderName: piiData.senderName || 'Khach hang',
    threadId: piiData.threadId || ''
  }
}];

// Smart Collection -- stateless parser for current-turn field detection
// CRITICAL-1 fix: does NOT accumulate state. AI Agent + Memory handle cross-turn.
const input = $input.first().json;
const msg = (input.customerMessage || '').toLowerCase();
const detected = {};
const svcMatch = msg.match(/(?:lam toc|lam nail|cham soc da|massage|uon|nuom|cat|goi|tay|tre hoa|nang co|dieu tri|rang su|laser|triet long|phun|moi|mi)/i);
if (svcMatch) detected.service = svcMatch[0];
const timeMatch = msg.match(/(sang|chieu|toi|t7|thu [2-7]|thu hai|thu ba|thu tu|thu nam|thu sau|thu bay|chu nhat|ngay mai|tuan sau|\d{1,2}[h:]\d{0,2})/i);
if (timeMatch) detected.time = timeMatch[0];
const nameMatch = msg.match(/(?:ten|em la|anh la|chi la|toi la)\s+([a-zà-ỹ]{2,20})\b/i);
if (nameMatch) detected.name = nameMatch[1];
const phoneMatch = msg.match(/\b0[35789]\d{8}\b/);
if (phoneMatch) detected.phone = phoneMatch[0];
const hasQuestionPattern = /gio|dia chi|o dau|bao nhieu|co khong|la gi|thoi gian|may gio|mo cua|dong cua/i.test(msg);
const hasBookingIntent = /dat|book|lich|dang ky|giu cho|xin lich|slot|muon lam|em muon/i.test(msg);
const hasNewFieldInfo = !!(detected.service || detected.name || detected.phone);
const isTopicChange = hasQuestionPattern && !hasBookingIntent && !hasNewFieldInfo;
let instruction = '';
if (isTopicChange) {
  instruction = '\n[HE THONG: Khach thay doi chu de. Tra loi cau hoi moi, sau do quay lai hoi dat lich neu phu hop.]';
} else {
  instruction = '\n[HE THONG: Neu chua co du thong tin dat lich (ten, so dien thoai, dich vu), hay hoi them.]';
  instruction += '\n[UU TIEN HOI: service -> name -> phone -> time (time la tuy chon)]';
  instruction += '\n[Khi du thong tin, tra loi DUNG JSON: {"booking": true, "name": "...", "phone": "...", "service": "...", "note": "..."}]';
}
return [{
  json: {
    ...input,
    currentDetected: detected,
    isTopicChange,
    systemInstruction: instruction
  }
}];

// Escalation Detection -- keyword patterns for handoff to human
// HIGH-4 fix: inline sequential check after AI Agent, not parallel branch
const input = $input.first().json;
const msg = (input.originalMessage || input.customerMessage || '').toLowerCase();

const PATTERNS = {
  human: /goi cho em|cho so dt|so dien thoai lien he|lien he truc tiep/i,
  complaint: /noi chuyen voi quan ly|giam doc|sep|khong hai long|phan nan|te qua|chui/i,
  distrust: /khong tin bot|nguoi that|nhan vien that|tu van vien|talk to human/i
};

let escalationType = null;
for (const [type, re] of Object.entries(PATTERNS)) {
  if (re.test(msg)) { escalationType = type; break; }
}

let ownerAlert = null;
let escalationReply = null;

if (escalationType === 'human') {
  ownerAlert = `KHACH MUON NOI CHUYEN TRUC TIEP\nSDT khach: ${input.senderId}\nTin nhan: "${msg}"\nHanh dong: Goi lai ngay!`;
  escalationReply = 'Day em la so ben em a! Em se cho nhan vien lien he voi anh/chị ngay nhé! 📞';
} else if (escalationType === 'complaint') {
  ownerAlert = `🔴 LEAD NONG -- Khach phan nan / khong hai long\nSDT khach: ${input.senderId}\nTin nhan: "${msg}"\nHanh dong: Xu ly ngay!`;
  escalationReply = 'Em xin lỗi nếu mình chưa làm anh/chị hài lòng. Để em kết nối với quản lý hỗ trợ anh/chị tốt hơn nhé!';
} else if (escalationType === 'distrust') {
  escalationReply = 'Day em la nhan vien tu van online cua spa a! Neu anh/chị muon gap truc tiep, em gui dia chi va hotline nhé: [SPA_PHONE]';
}

return [{
  json: {
    ...input,
    isEscalation: !!escalationType,
    escalationType,
    ownerAlert,
    escalationReply
  }
}];

// Format escalation alert
const data = $input.first().json;
return [{
  json: {
    ownerMessage: data.ownerAlert,
    threadId: data.threadId
  }
}];

// Parse Booking
const triggerData = $('Zalo Message Trigger').item.json;
const senderId = triggerData.data?.fromId || triggerData.data?.senderId || 'unknown';
const senderName = triggerData.data?.senderName || 'Khach hang';
const customerMessage = triggerData.data?.content || triggerData.data?.text || '';
const threadId = triggerData.threadId || '';
const timestamp = new Date().toLocaleString('vi-VN', { timeZone: 'Asia/Ho_Chi_Minh' });

const aiOutput = $input.first().json.output || '';
const hasError = !aiOutput || $input.first().json.error;


if (hasError) {
  return [{
    json: {
      isBooking: false,
      bookingData: null,
      replyText: 'Day hien em dang ban ho tro khach khac. Anh/chị de lai so dien thoai, em goi lai tu van cho anh/chị ngay nhé! 💖',
      senderId, senderName, rawAiOutput: aiOutput, threadId, isError: true,
      messageType: 'Fallback (loi API)', customerMessage, timestamp
    }
  }];
}

let isBooking = false;
let bookingData = null;
let replyText = '';

try {
  const jsonMatch = aiOutput.match(/\{[\s\S]*"booking"[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    if (parsed.booking === true && parsed.phone) {
      isBooking = true;
      bookingData = {
        name: parsed.name || 'Khong ro',
        phone: parsed.phone || '',
        service: parsed.service || 'Khong ro',
        note: parsed.note || '',
        timestamp
      };
      replyText = `✅ Em da ghi nhan lich hen cua anh/chị ${bookingData.name} roi a!\n\n📋 Thong tin:\n• Dich vu: ${bookingData.service}\n• Ghi chu: ${bookingData.note || 'Khong co'}\n\nEm se lien he xac nhan lai voi anh/chị trong thoi gian som nhat. 💖`;
    }
  }
} catch (e) {
  isBooking = false;
}

if (!isBooking) replyText = aiOutput;

let messageType = 'Tu van';
if (isBooking) messageType = 'Dat lich';
else {
  const lowerMsg = customerMessage.toLowerCase();
  if (lowerMsg.match(/gia|bao nhieu|phi|dat|re/)) messageType = 'Hoi gia';
  else if (lowerMsg.match(/phan nan|te|kem|chui|buc/)) messageType = 'Phan nan';
  else if (lowerMsg.match(/gio|dia chi|o dau|map/)) messageType = 'Hoi thong tin';
}

return [{
  json: {
    isBooking, bookingData, replyText, senderId, senderName,
    rawAiOutput: aiOutput, threadId, isError: false, messageType, customerMessage, timestamp
  }
}];

// Unmask Reply -- restore real names/phones in customer-facing messages
// HIGH-2 fix: customer sees their real name, not [NAME_0]
const items = $input.all();
const data = items[0].json;
let reply = data.replyText || '';
const phoneMap = data.phoneMap || [];
const nameMap = data.nameMap || [];

phoneMap.forEach((entry) => {
  const escaped = entry.mask.replace(/[[\]]/g, '\\$&');
  reply = reply.replace(new RegExp(escaped, 'g'), entry.real);
  if (entry.mask === '[PHONE_0]') reply = reply.replace(/\[PHONE\]/g, entry.real);
});

nameMap.forEach((entry) => {
  const escaped = entry.mask.replace(/[[\]]/g, '\\$&');
  reply = reply.replace(new RegExp(escaped, 'g'), entry.real);
});

return [{
  json: { ...data, replyText: reply }
}];

// Duplicate Check -- CRITICAL-4: cross-node phone access
const existingRows = $input.all();
const smartCollection = $('Code - Smart Collection').first().json;
const parseBooking = $('Parse Booking').first().json;
const phone = smartCollection.currentDetected?.phone || parseBooking.bookingData?.phone;

let action = 'insert';
let reply = '';
let existingRow = null;

const match = existingRows.find(r => {
  const rowPhone = r.json['So dien thoai'] || r.json['Số điện thoại'] || '';
  return rowPhone === phone;
});

if (match) {
  existingRow = match.json;
  const status = existingRow['Trang thai'] || existingRow['Trạng thái'] || '';
  if (status === 'Moi dat' || status === 'Mới đặt') { action = 'update'; reply = 'Em đã cập nhật lịch cho anh/chị rồi ạ! 💖'; }
  else if (status === 'Da xac nhan' || status === 'Đã xác nhận') { action = 'reject'; reply = 'Lịch đã xác nhận! Gọi: [SPA_PHONE] 📞'; }
  else if (status === 'Hoan thanh' || status === 'Hoàn thành') { action = 'insert'; reply = ''; }
}

return [{
  json: { ...$input.first().json, duplicateAction: action, existingRow, duplicateReply: reply, bookingData: parseBooking.bookingData }
}];

// Business Hours -- HCM timezone
// MEDIUM-6 fix: hour >= 8 && hour <= 20 (includes 20:xx)
const now = new Date();
const hcmNow = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Ho_Chi_Minh' }));
const hour = hcmNow.getHours();
const isBusinessHours = hour >= 8 && hour <= 20;
return [{
  json: { ...$input.first().json, isBusinessHours, currentHourHCM: hour }
}];

// Deferred Reply -- outside business hours
const data = $input.first().json;
const b = data.bookingData || {};
const reply = `Dạ em đã ghi nhận lịch của anh/chị rồi ạ! ✅\nDịch vụ: ${b.service || 'Chưa rõ'}\nEm sẽ xác nhận lại vào sáng mai lúc 8h. 💖`;
return [{
  json: { ...data, replyText: reply, threadId: data.threadId || '' }
}];

// Tao tin nhan bao chu spa
const data = $input.first().json;
const b = data.bookingData;
const ownerMsg = `🔔 KHACH HANG MOI DAT LICH

👤 Ten: ${b.name}
📞 SDT: ${b.phone}
💇 Dich vu: ${b.service}
📝 Ghi chu: ${b.note || 'Khong co'}
⏰ Thoi gian: ${b.timestamp}

Xac nhan lich hen voi khach ngay nhe!`;
return [{
  json: { ownerMessage: ownerMsg, threadId: data.threadId }
}];
